import React, { useState, useEffect, useCallback } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import './UserProfile.css';

const BADGE_COLORS = {
  'First Supporter 🌟': '#f59e0b',
  'Hero Donor 🦸': '#6366f1',
  'Community Champion 🏆': '#10b981',
  'Loyal Supporter 💚': '#22c55e'
};

const XP_LEVELS = [
  { level: 1, min: 0, max: 99, label: 'Newcomer' },
  { level: 2, min: 100, max: 299, label: 'Supporter' },
  { level: 3, min: 300, max: 599, label: 'Champion' },
  { level: 4, min: 600, max: 999, label: 'Hero' },
  { level: 5, min: 1000, max: Infinity, label: 'Legend' }
];

const getLevel = (xp) => XP_LEVELS.find((l) => xp >= l.min && xp <= l.max) || XP_LEVELS[0];

const timeAgo = (dateStr) => {
  const diff = Date.now() - new Date(dateStr).getTime();
  const mins = Math.floor(diff / 60000);
  if (mins < 60) return `${mins}m ago`;
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return `${hrs}h ago`;
  return `${Math.floor(hrs / 24)}d ago`;
};

const UserProfile = () => {
  const { user: authUser } = useAuth();
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  const fetchProfile = useCallback(async () => {
    try {
      setLoading(true);
      setError('');
      const { data } = await axios.get('/api/users/profile');
      setProfile(data);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to load profile.');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchProfile(); }, [fetchProfile]);

  if (loading) {
    return (
      <div className="loading-state" style={{ minHeight: '60vh' }}>
        <div className="spinner spinner-lg" />
        <p style={{ color: 'var(--text-secondary)' }}>Loading profile...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="container" style={{ paddingTop: '4rem', textAlign: 'center' }}>
        <div className="alert alert-error" style={{ maxWidth: '500px', margin: '0 auto 1.5rem' }}>
          <span>⚠️</span><p>{error}</p>
        </div>
        <button className="btn btn-secondary" onClick={fetchProfile}>Retry</button>
      </div>
    );
  }

  const { user, stats, donations, activeSubscriptions } = profile;
  const level = getLevel(stats.xpPoints);
  const nextLevel = XP_LEVELS.find((l) => l.level === level.level + 1);
  const xpProgress = nextLevel
    ? Math.round(((stats.xpPoints - level.min) / (nextLevel.min - level.min)) * 100)
    : 100;

  const initials = (authUser?.name || user?.name || 'U').split(' ').map((n) => n[0]).join('').toUpperCase().substring(0, 2);

  return (
    <div className="profile-page">
      <div className="container">

        {/* Header */}
        <div className="profile-header-card" id="profile-header">
          <div className="profile-avatar-large">{initials}</div>
          <div className="profile-header-info">
            <h1 className="profile-name">{user.name}</h1>
            <p className="profile-email">{user.email}</p>
            <div className="profile-level-badge">
              <span className="level-icon">⭐</span>
              <span>Level {level.level} — {level.label}</span>
            </div>
          </div>
        </div>

        {/* XP Bar */}
        <div className="xp-card" id="xp-bar-card">
          <div className="xp-label-row">
            <span className="xp-label">XP Points</span>
            <span className="xp-value">{stats.xpPoints} {nextLevel ? `/ ${nextLevel.min} XP` : '(Max Level)'}</span>
          </div>
          <div className="xp-bar-track">
            <div className="xp-bar-fill" style={{ width: `${xpProgress}%` }} />
          </div>
          {nextLevel && (
            <p className="xp-hint">
              {nextLevel.min - stats.xpPoints} XP to reach <strong>{nextLevel.label}</strong>
            </p>
          )}
        </div>

        {/* Stats Row */}
        <div className="profile-stats-row" id="profile-stats">
          <div className="profile-stat-card">
            <div className="psc-icon">💰</div>
            <div className="psc-value">₹{stats.totalDonated.toLocaleString('en-IN')}</div>
            <div className="psc-label">Total Donated</div>
          </div>
          <div className="profile-stat-card">
            <div className="psc-icon">🎯</div>
            <div className="psc-value">{stats.campaignsSupported}</div>
            <div className="psc-label">Campaigns Supported</div>
          </div>
          <div className="profile-stat-card">
            <div className="psc-icon">🔄</div>
            <div className="psc-value">{activeSubscriptions?.length || 0}</div>
            <div className="psc-label">Active Subscriptions</div>
          </div>
          <div className="profile-stat-card">
            <div className="psc-icon">🏅</div>
            <div className="psc-value">{stats.badges.length}</div>
            <div className="psc-label">Badges Earned</div>
          </div>
        </div>

        <div className="profile-content-grid">

          {/* Badges Section */}
          <div className="profile-section-card" id="badges-section">
            <h2 className="section-heading">🏅 My Badges</h2>
            {stats.badges.length === 0 ? (
              <div className="empty-badges">
                <p>No badges yet. Start donating to earn your first badge! 🌟</p>
                <Link to="/" className="btn btn-primary btn-sm">Explore Campaigns</Link>
              </div>
            ) : (
              <div className="badges-grid" id="badges-grid">
                {stats.badges.map((badge, i) => (
                  <div
                    key={i}
                    className="badge-card"
                    style={{ borderColor: BADGE_COLORS[badge] || '#a8b4c0' }}
                    id={`badge-${i}`}
                  >
                    <div className="badge-emoji" style={{ background: `${BADGE_COLORS[badge] || '#e2e8f0'}22` }}>
                      {badge.split(' ').pop()}
                    </div>
                    <div className="badge-name">{badge.replace(/[^\w\s]/gu, '').trim()}</div>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Active Subscriptions */}
          {activeSubscriptions && activeSubscriptions.length > 0 && (
            <div className="profile-section-card" id="subscriptions-section">
              <h2 className="section-heading">🔄 Active Monthly Donations</h2>
              <div className="sub-list">
                {activeSubscriptions.map((sub) => (
                  <div key={sub._id} className="sub-row">
                    <div className="sub-info">
                      <div className="sub-campaign">{sub.campaign?.title || 'Campaign'}</div>
                      <div className="sub-meta">₹{sub.amount.toLocaleString('en-IN')}/month · {sub.status}</div>
                    </div>
                    <span className="badge-green-pill">Monthly Supporter 🔄</span>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Donation History */}
          <div className="profile-section-card profile-full-width" id="donation-history-section">
            <h2 className="section-heading">💙 Donation History</h2>
            {donations.length === 0 ? (
              <div className="empty-badges">
                <p>You haven't donated yet. Every rupee makes a difference!</p>
                <Link to="/" className="btn btn-primary btn-sm">Find a Campaign</Link>
              </div>
            ) : (
              <div className="donation-history-list" id="donation-history-list">
                {donations.map((d) => (
                  <div key={d._id} className="donation-history-row">
                    <div className="dhr-campaign-img">
                      {d.campaign?.imageUrl
                        ? <img src={d.campaign.imageUrl} alt={d.campaign.title} onError={(e) => { e.target.style.display = 'none'; }} />
                        : <span className="dhr-placeholder">💙</span>
                      }
                    </div>
                    <div className="dhr-info">
                      <div className="dhr-title">
                        {d.campaign?._id
                          ? <Link to={`/campaigns/${d.campaign._id}`}>{d.campaign.title}</Link>
                          : <span>Campaign</span>
                        }
                        {d.isRecurring && <span className="recurring-tag">🔄 Recurring</span>}
                      </div>
                      {d.message && <div className="dhr-message">"{d.message}"</div>}
                      <div className="dhr-meta">{timeAgo(d.createdAt)}</div>
                    </div>
                    <div className="dhr-amount">₹{d.amount.toLocaleString('en-IN')}</div>
                  </div>
                ))}
              </div>
            )}
          </div>

        </div>
      </div>
    </div>
  );
};

export default UserProfile;
